    public var tokenDurationScales: [Double]?
    public var tokenF0Biases: [Double]?

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(speedMultiplier: Double?, speedBias: Double?, gainMultiplier: Double?, gainBias: Double?, castingProfile: CastingProfile?, speakerLock: String?, pauseMultiplier: Double?, pronunciationOverride: String?, pitch: Double?, tokenDurationScales: [Double]?, tokenF0Biases: [Double]?) {
        self.speedMultiplier = speedMultiplier
        self.speedBias = speedBias
        self.gainMultiplier = gainMultiplier
        self.gainBias = gainBias
        self.castingProfile = castingProfile
        self.speakerLock = speakerLock
        self.pauseMultiplier = pauseMultiplier
        self.pronunciationOverride = pronunciationOverride
        self.pitch = pitch
        self.tokenDurationScales = tokenDurationScales
        self.tokenF0Biases = tokenF0Biases
    }
}



extension ProsodyAcoustics: Equatable, Hashable {
    public static func ==(lhs: ProsodyAcoustics, rhs: ProsodyAcoustics) -> Bool {
        if lhs.speedMultiplier != rhs.speedMultiplier {
            return false
        }
        if lhs.speedBias != rhs.speedBias {
            return false
        }
        if lhs.gainMultiplier != rhs.gainMultiplier {
            return false
        }
        if lhs.gainBias != rhs.gainBias {
            return false
        }
        if lhs.castingProfile != rhs.castingProfile {
            return false
        }
        if lhs.speakerLock != rhs.speakerLock {
