        }
        if lhs.pauseMultiplier != rhs.pauseMultiplier {
            return false
        }
        if lhs.pronunciationOverride != rhs.pronunciationOverride {
            return false
        }
        if lhs.pitch != rhs.pitch {
            return false
        }
        if lhs.tokenDurationScales != rhs.tokenDurationScales {
            return false
        }
        if lhs.tokenF0Biases != rhs.tokenF0Biases {
            return false
        }
        return true
    }

