        hasher.combine(speedMultiplier)
        hasher.combine(speedBias)
        hasher.combine(gainMultiplier)
        hasher.combine(gainBias)
        hasher.combine(castingProfile)
        hasher.combine(speakerLock)
        hasher.combine(pauseMultiplier)
        hasher.combine(pronunciationOverride)
        hasher.combine(pitch)
        hasher.combine(tokenDurationScales)
        hasher.combine(tokenF0Biases)
    }
