public protocol ProsodyPhraser : AnyObject {
    
    func spans(text: String, emotion: EmotionVector)  -> [ProsodySpan]
    
}

// Magic number for the Rust proxy to call using the same mechanism as every other method,
// to free the callback once it's dropped by Rust.
private let IDX_CALLBACK_FREE: Int32 = 0
// Callback return codes
private let UNIFFI_CALLBACK_SUCCESS: Int32 = 0
private let UNIFFI_CALLBACK_ERROR: Int32 = 1
private let UNIFFI_CALLBACK_UNEXPECTED_ERROR: Int32 = 2

// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceProsodyPhraser {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    static var vtable: UniffiVTableCallbackInterfaceProsodyPhraser = UniffiVTableCallbackInterfaceProsodyPhraser(
        spans: { (
            uniffiHandle: UInt64,
            text: RustBuffer,
            emotion: RustBuffer,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> [ProsodySpan] in
                guard let uniffiObj = try? FfiConverterCallbackInterfaceProsodyPhraser.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return uniffiObj.spans(
                     text: try FfiConverterString.lift(text),
                     emotion: try FfiConverterTypeEmotionVector.lift(emotion)
                )
            }

            
            let writeReturn = { uniffiOutReturn.pointee = FfiConverterSequenceTypeProsodySpan.lower($0) }
            uniffiTraitInterfaceCall(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn
            )
        },
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            let result = try? FfiConverterCallbackInterfaceProsodyPhraser.handleMap.remove(handle: uniffiHandle)
            if result == nil {
                print("Uniffi callback interface ProsodyPhraser: handle missing in uniffiFree")
            }
        }
    )
}

private func uniffiCallbackInitProsodyPhraser() {
    uniffi_stage_fn_init_callback_vtable_prosodyphraser(&UniffiCallbackInterfaceProsodyPhraser.vtable)
}

// FfiConverter protocol for callback interfaces
fileprivate struct FfiConverterCallbackInterfaceProsodyPhraser {
    fileprivate static var handleMap = UniffiHandleMap<ProsodyPhraser>()
}

extension FfiConverterCallbackInterfaceProsodyPhraser : FfiConverter {
    typealias SwiftType = ProsodyPhraser
    typealias FfiType = UInt64

    public static func lift(_ handle: UInt64) throws -> SwiftType {
        try handleMap.get(handle: handle)
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SwiftType {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func lower(_ v: SwiftType) -> UInt64 {
        return handleMap.insert(obj: v)
    }

    public static func write(_ v: SwiftType, into buf: inout [UInt8]) {
        writeInt(&buf, lower(v))
    }
}

